import React, { createContext, useContext, useReducer, useEffect } from 'react';
import { taskHelpers } from '../services/api';

// Initial state
const initialState = {
  // Current user role/department
  currentRole: null,

  // Tasks data
  tasks: [],
  loading: false,
  error: null,

  // Selected task for details
  selectedTask: null,
  selectedTaskLoading: false,
  selectedTaskError: null,

  // Filters
  filters: {
    slaFilter: '',
    priorityFilter: '',
    stateFilter: '',
  },

  // Statistics
  stats: {
    total: 0,
    onTime: 0,
    approaching: 0,
    breached: 0,
    highPriority: 0,
    mediumPriority: 0,
    lowPriority: 0,
  },
};

// Action types
const actionTypes = {
  SET_CURRENT_ROLE: 'SET_CURRENT_ROLE',
  SET_LOADING: 'SET_LOADING',
  SET_ERROR: 'SET_ERROR',
  SET_TASKS: 'SET_TASKS',
  SET_SELECTED_TASK: 'SET_SELECTED_TASK',
  SET_SELECTED_TASK_LOADING: 'SET_SELECTED_TASK_LOADING',
  SET_SELECTED_TASK_ERROR: 'SET_SELECTED_TASK_ERROR',
  SET_FILTERS: 'SET_FILTERS',
  UPDATE_STATS: 'UPDATE_STATS',
  CLEAR_ERROR: 'CLEAR_ERROR',
  REFRESH_TASKS: 'REFRESH_TASKS',
};

// Reducer function
const taskReducer = (state, action) => {
  switch (action.type) {
    case actionTypes.SET_CURRENT_ROLE:
      return {
        ...state,
        currentRole: action.payload,
        tasks: [], // Clear tasks when role changes
        error: null,
      };

    case actionTypes.SET_LOADING:
      return {
        ...state,
        loading: action.payload,
      };

    case actionTypes.SET_ERROR:
      return {
        ...state,
        error: action.payload,
        loading: false,
      };

    case actionTypes.SET_TASKS:
      return {
        ...state,
        tasks: action.payload,
        loading: false,
        error: null,
      };

    case actionTypes.SET_SELECTED_TASK:
      return {
        ...state,
        selectedTask: action.payload,
        selectedTaskLoading: false,
        selectedTaskError: null,
      };

    case actionTypes.SET_SELECTED_TASK_LOADING:
      return {
        ...state,
        selectedTaskLoading: action.payload,
      };

    case actionTypes.SET_SELECTED_TASK_ERROR:
      return {
        ...state,
        selectedTaskError: action.payload,
        selectedTaskLoading: false,
      };

    case actionTypes.SET_FILTERS:
      return {
        ...state,
        filters: {
          ...state.filters,
          ...action.payload,
        },
      };

    case actionTypes.UPDATE_STATS:
      return {
        ...state,
        stats: action.payload,
      };

    case actionTypes.CLEAR_ERROR:
      return {
        ...state,
        error: null,
        selectedTaskError: null,
      };

    default:
      return state;
  }
};

// Create context
const TaskContext = createContext();

// Provider component
export const TaskProvider = ({ children }) => {
  const [state, dispatch] = useReducer(taskReducer, initialState);

  // Calculate statistics from tasks
  const calculateStats = (tasks) => {
    const stats = {
      total: tasks.length,
      onTime: tasks.filter(task => task.slaStatus === 'ON_TIME').length,
      approaching: tasks.filter(task => task.slaStatus === 'APPROACHING').length,
      breached: tasks.filter(task => task.slaStatus === 'BREACHED').length,
      highPriority: tasks.filter(task => task.priority === 'P1').length,
      mediumPriority: tasks.filter(task => task.priority === 'P2').length,
      lowPriority: tasks.filter(task => task.priority === 'P3').length,
    };

    dispatch({ type: actionTypes.UPDATE_STATS, payload: stats });
    return stats;
  };

  // Actions
  const actions = {
    // Set current user role
    setCurrentRole: (role) => {
      dispatch({ type: actionTypes.SET_CURRENT_ROLE, payload: role });
    },

    // Fetch tasks for current role
    fetchTasks: async (candidateGroup = null) => {
      try {
        dispatch({ type: actionTypes.SET_LOADING, payload: true });
        dispatch({ type: actionTypes.CLEAR_ERROR });

        const group = candidateGroup || state.currentRole;
        if (!group) {
          throw new Error('No candidate group specified');
        }

        const response = await taskHelpers.getTasksByGroup(group);
        const tasks = response.data;

        dispatch({ type: actionTypes.SET_TASKS, payload: tasks });
        calculateStats(tasks);

        return tasks;
      } catch (error) {
        const errorMessage = error.response?.data?.error || error.message || 'Failed to fetch tasks';
        dispatch({ type: actionTypes.SET_ERROR, payload: errorMessage });
        throw error;
      }
    },

    // Fetch task details
    fetchTaskDetails: async (taskId) => {
      try {
        dispatch({ type: actionTypes.SET_SELECTED_TASK_LOADING, payload: true });
        dispatch({ type: actionTypes.CLEAR_ERROR });

        const response = await taskHelpers.getTasksByGroup(state.currentRole);
        const task = response.data.find(t => t.id === taskId);

        if (!task) {
          throw new Error('Task not found');
        }

        dispatch({ type: actionTypes.SET_SELECTED_TASK, payload: task });
        return task;
      } catch (error) {
        const errorMessage = error.response?.data?.error || error.message || 'Failed to fetch task details';
        dispatch({ type: actionTypes.SET_SELECTED_TASK_ERROR, payload: errorMessage });
        throw error;
      }
    },

    // Claim task
    claimTask: async (taskId, userId) => {
      try {
        const { complaintAPI } = await import('../services/api');
        await complaintAPI.claimTask(taskId, userId);

        // Refresh tasks after claiming
        await actions.fetchTasks();
        return true;
      } catch (error) {
        const errorMessage = error.response?.data?.error || error.message || 'Failed to claim task';
        dispatch({ type: actionTypes.SET_ERROR, payload: errorMessage });
        throw error;
      }
    },

    // Complete task
    completeTask: async (taskId, variables = {}) => {
      try {
        const { complaintAPI } = await import('../services/api');
        await complaintAPI.completeTask(taskId, variables);

        // Refresh tasks after completing
        await actions.fetchTasks();
        return true;
      } catch (error) {
        const errorMessage = error.response?.data?.error || error.message || 'Failed to complete task';
        dispatch({ type: actionTypes.SET_ERROR, payload: errorMessage });
        throw error;
      }
    },

    // Update filters
    updateFilters: (filters) => {
      dispatch({ type: actionTypes.SET_FILTERS, payload: filters });
    },

    // Clear errors
    clearError: () => {
      dispatch({ type: actionTypes.CLEAR_ERROR });
    },

    // Refresh tasks
    refreshTasks: () => {
      if (state.currentRole) {
        actions.fetchTasks();
      }
    },
  };

  // Auto-refresh tasks every 30 seconds
  useEffect(() => {
    if (state.currentRole) {
      const interval = setInterval(() => {
        actions.fetchTasks();
      }, 30000); // 30 seconds

      return () => clearInterval(interval);
    }
  }, [state.currentRole]);

  const value = {
    ...state,
    ...actions,
  };

  return (
    <TaskContext.Provider value={value}>
      {children}
    </TaskContext.Provider>
  );
};

// Custom hook to use the context
export const useTask = () => {
  const context = useContext(TaskContext);
  if (!context) {
    throw new Error('useTask must be used within a TaskProvider');
  }
  return context;
};

export default TaskContext;
